+fn parseDuration(s: []const u8) ?i64 {
+    if (s.len < 2) return null;
+    const unit = s[s.len - 1];
+    const num_str = s[0 .. s.len - 1];
+    const num = std.fmt.parseInt(i64, num_str, 10) catch return null;
+    if (num <= 0) return null;
+    return switch (unit) {
+        'm' => num * 60,
+        'h' => num * 3600,
+        'd' => num * 86400,
+        else => null,
+    };
